"use strict";(globalThis.webpackChunknebula=globalThis.webpackChunknebula||[]).push([[3213],{3778(e){e.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"MC1248389","metadata":{"permalink":"/Nebula.KB-dev/news/MC1248389","source":"@site/blog/2026-03-11-MC1248389/index.md","title":"Retirement of -Credential parameter when connecting to Exchange Online PowerShell","description":"Introduction","date":"2026-03-11T00:00:00.000Z","tags":[{"inline":false,"label":"Microsoft","permalink":"/Nebula.KB-dev/news/tags/microsoft","description":"Microsoft"},{"inline":false,"label":"Microsoft Exchange","permalink":"/Nebula.KB-dev/news/tags/exchange","description":"Microsoft Exchange in Cloud"},{"inline":false,"label":"PowerShell","permalink":"/Nebula.KB-dev/news/tags/powershell","description":"PowerShell"},{"inline":false,"label":"Nebula.Core","permalink":"/Nebula.KB-dev/news/tags/core","description":"Updates concerning Nebula.Core"}],"readingTime":0.93,"hasTruncateMarker":true,"authors":[{"name":"Giovanni Solone","title":"Former Batman, co-founder of Marvellous Codeworks, dad of Nebula modules","url":"https://gioxx.org","page":{"permalink":"/Nebula.KB-dev/news/authors/gioxx"},"socials":{"x":"https://x.com/gioxx","linkedin":"https://www.linkedin.com/in/gioxx/","github":"https://github.com/gioxx"},"imageURL":"https://github.com/gioxx.png","key":"gioxx"}],"frontMatter":{"slug":"MC1248389","title":"Retirement of -Credential parameter when connecting to Exchange Online PowerShell","authors":["gioxx"],"tags":["microsoft","exchange","powershell","core"]},"unlisted":false},"content":"### Introduction\\n\\nMicrosoft is retiring the [-Credential](https://learn.microsoft.com/powershell/module/exchangepowershell/connect-exchangeonline?view=exchange-ps#-credential) parameter used when connecting to Exchange Online PowerShell. Starting with module versions released in July 2026 and later, the -Credential parameter will be removed from both [Connect-ExchangeOnline](https://learn.microsoft.com/powershell/module/exchangepowershell/connect-exchangeonline?view=exchange-ps) and [Connect-IppsSession](https://learn.microsoft.com/powershell/module/exchangepowershell/connect-ippssession?view=exchange-ps) cmdlets. Organizations using this parameter in automation scripts must migrate to a supported authentication method before that date. This change improves security by moving away from legacy authentication methods that do not support modern protections such as multifactor authentication (MFA).\\n\\n\x3c!-- truncate --\x3e\\n\\nSimply add Markdown files (or folders) to the `blog` directory.\\n\\nRegular blog authors can be added to `authors.yml`.\\n\\nThe blog post date can be extracted from filenames, such as:\\n\\n- `2019-05-30-welcome.md`\\n- `2019-05-30-welcome/index.md`\\n\\nA blog post folder can be convenient to co-locate blog post images:\\n\\nThe blog supports tags as well!\\n\\n**And if you don\'t want a blog**: just delete this directory, and use `blog: false` in your Docusaurus config."}]}}')}}]);